# Cinematic Landing Hero v2

Full-page GSAP ScrollTrigger cinematic hero that pins the section for 7000px of scroll, flies a deep-blue card in from below to fill the viewport, reveals an iPhone mockup with counter animation and progress ring, then pulls back and transitions to CTA buttons. Includes mouse-driven 3D tilt, card mouse-light sheen, film grain, grid overlay, and glass badges. Fully configurable via props.

## Use when
- Building a product landing page with a dramatic multi-stage scroll-driven reveal.
- Creating a dark, immersive hero that transitions from a headline to a product demo card.
- Delivering a first-load reveal with a cinematic card fly-in and iPhone mockup showcase.
- Emphasizing a value proposition via a full-viewport scroll-pinned storytelling experience.

## Stack
- Framework: react
- Libraries: gsap
- Requires: tailwind

## Install
```bash
gsap
```

## Component — cinematic-landing-hero.tsx
```tsx
// src/components/ui/cinematic-hero.tsx
"use client";

import React, { useEffect, useRef } from "react";
import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { cn } from "@/lib/utils";

if (typeof window !== "undefined") {
  gsap.registerPlugin(ScrollTrigger);
}

// INJECTED_STYLES constant contains all class definitions:
// .gsap-reveal, .film-grain, .bg-grid-theme, .text-3d-matte, .text-silver-matte,
// .text-card-silver-matte, .premium-depth-card, .card-sheen, .iphone-bezel,
// .hardware-btn, .screen-glare, .widget-depth, .floating-ui-badge,
// .btn-modern-light, .btn-modern-dark, .progress-ring

export interface CinematicHeroProps extends React.HTMLAttributes<HTMLDivElement> {
  brandName?: string;
  tagline1?: string;
  tagline2?: string;
  cardHeading?: string;
  cardDescription?: React.ReactNode;
  metricValue?: number;
  metricLabel?: string;
  ctaHeading?: string;
  ctaDescription?: string;
}

export function CinematicHero({ 
  brandName = "Sobers",
  tagline1 = "Track the journey,",
  tagline2 = "not just the days.",
  // ... additional props with defaults
  className, 
  ...props 
}: CinematicHeroProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const mainCardRef = useRef<HTMLDivElement>(null);
  const mockupRef = useRef<HTMLDivElement>(null);

  // Mouse 3D tilt + card sheen with rAF
  useEffect(() => { /* ... */ }, []);

  // GSAP ScrollTrigger cinematic timeline (7000px pin)
  useEffect(() => { /* ... */ }, [metricValue]);

  return (
    <div ref={containerRef} className={cn("relative w-screen h-screen overflow-hidden ...", className)} style={{ perspective: "1500px" }} {...props}>
      <style dangerouslySetInnerHTML={{ __html: INJECTED_STYLES }} />
      {/* film-grain, bg-grid-theme, hero-text-wrapper, cta-wrapper, main-card with iPhone mockup */}
    </div>
